const SANS = "Unbounded, system-ui, -apple-system, BlinkMacSystemFont, Segoe UI, sans-serif";
const MONO = "Geist Mono, ui-monospace, SFMono-Regular, Menlo, Consolas, monospace";

function themeColors() {
  const isDark = document.documentElement.classList.contains("dark");
  return {
    bg: isDark ? "#0A0C10" : "#F5F0EA",
    text: isDark ? "#ffffff" : "#18181b",
    muted: isDark ? "#71717a" : "#52525b",
    subtle: isDark ? "#a1a1aa" : "#71717a",
    green: isDark ? "#10b981" : "#047857",
    greenSoft: isDark ? "#34d399" : "#059669",
    amber: isDark ? "#fbbf24" : "#b45309",
    red: isDark ? "#f87171" : "#dc2626",
    gridLine: isDark ? "rgba(255,255,255,0.055)" : "rgba(0,0,0,0.06)",
    cardBg: isDark ? "rgba(255,255,255,0.025)" : "rgba(0,0,0,0.03)",
    cardBorder: isDark ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.08)",
    glowGreen: isDark ? "rgba(16,185,129,0.15)" : "rgba(5,150,105,0.10)",
    glowAmber: isDark ? "rgba(245,158,11,0.10)" : "rgba(180,83,9,0.08)",
  };
}

const CARD = { width: 1200, height: 630 };

function roundRect(ctx, x, y, w, h, r) {
  const radius = Math.min(r, w / 2, h / 2);
  ctx.beginPath();
  ctx.moveTo(x + radius, y);
  ctx.arcTo(x + w, y, x + w, y + h, radius);
  ctx.arcTo(x + w, y + h, x, y + h, radius);
  ctx.arcTo(x, y + h, x, y, radius);
  ctx.arcTo(x, y, x + w, y, radius);
  ctx.closePath();
}

function fillRoundRect(ctx, x, y, w, h, r, fill, stroke = null) {
  roundRect(ctx, x, y, w, h, r);
  ctx.fillStyle = fill;
  ctx.fill();
  if (stroke) {
    ctx.strokeStyle = stroke;
    ctx.lineWidth = 1;
    ctx.stroke();
  }
}

function drawGrid(ctx, w, h, color) {
  ctx.save();
  ctx.globalAlpha = 1;
  ctx.strokeStyle = color;
  ctx.lineWidth = 1;
  for (let x = 0; x <= w; x += 40) {
    ctx.beginPath();
    ctx.moveTo(x, 0);
    ctx.lineTo(x, h);
    ctx.stroke();
  }
  for (let y = 0; y <= h; y += 40) {
    ctx.beginPath();
    ctx.moveTo(0, y);
    ctx.lineTo(w, y);
    ctx.stroke();
  }
  ctx.restore();
}

function drawGlow(ctx, x, y, radius, color, w, h) {
  const gradient = ctx.createRadialGradient(x, y, 0, x, y, radius);
  gradient.addColorStop(0, color);
  gradient.addColorStop(1, "rgba(0,0,0,0)");
  ctx.fillStyle = gradient;
  ctx.fillRect(0, 0, w, h);
}

function drawLabel(ctx, text, x, y, color) {
  ctx.font = `700 11px ${MONO}`;
  ctx.fillStyle = color;
  ctx.fillText(String(text || "").toUpperCase(), x, y);
}

function getAccuracyStyle(label, t) {
  const styles = {
    Trustworthy: { color: t.greenSoft, bg: t.green + "1A", border: t.green + "66" },
    Suspicious: { color: t.amber, bg: t.amber + "1A", border: t.amber + "66" },
    Flagged: { color: t.red, bg: t.red + "1A", border: t.red + "66" },
    Neutral: { color: t.subtle, bg: t.cardBg, border: t.cardBorder },
  };
  return styles[label] || styles.Neutral;
}

export async function renderSellerCardToBlob(seller) {
  const { name, totalListings, validListings, avgMarkupPercent, overpricedRatio, accuracyLabel, isBlacklisted } = seller || {};
  const t = themeColors();
  const v = CARD;
  return new Promise((resolve, reject) => {
    const canvas = document.createElement("canvas");
    canvas.width = v.width;
    canvas.height = v.height;
    const ctx = canvas.getContext("2d");
    if (!ctx) { reject(new Error("Canvas is unavailable")); return; }

    ctx.fillStyle = t.bg;
    ctx.fillRect(0, 0, v.width, v.height);
    drawGrid(ctx, v.width, v.height, t.gridLine);
    drawGlow(ctx, v.width - 200, 100, 450, t.glowGreen, v.width, v.height);
    drawGlow(ctx, 100, v.height - 150, 350, t.glowAmber, v.width, v.height);

    // Header
    ctx.font = `800 13px ${MONO}`;
    ctx.fillStyle = t.green;
    ctx.fillText("CASTIA — SELLER", 74, 50);
    ctx.fillStyle = t.green;
    ctx.beginPath();
    ctx.arc(62, 46, 4, 0, Math.PI * 2);
    ctx.fill();
    ctx.fillStyle = t.muted;
    ctx.textAlign = "right";
    ctx.fillText(new Date().toUTCString().slice(5, 16), v.width - 56, 50);
    ctx.textAlign = "left";

    // Seller name
    ctx.font = `900 52px ${SANS}`;
    ctx.fillStyle = t.text;
    const nameDisplay = name || "Unknown Seller";
    ctx.fillText(nameDisplay.length > 18 ? nameDisplay.slice(0, 15) + "..." : nameDisplay, 56, 130);

    // Accuracy badge
    const badge = getAccuracyStyle(accuracyLabel, t);
    const label = (accuracyLabel || "Neutral").toUpperCase();
    ctx.font = `800 14px ${MONO}`;
    ctx.fillStyle = badge.color;
    fillRoundRect(ctx, v.width - 200, 95, 140, 32, 6, badge.bg, badge.border);
    ctx.fillText(label, v.width - 190, 118);

    // Stats grid
    const contentX = 56;
    const contentY = 190;
    const contentWidth = v.width - contentX * 2;

    function drawStatBox(labelText, value, x, y, note = "") {
      fillRoundRect(ctx, x, y, (contentWidth - 20) / 2, 110, 10, t.cardBg, t.cardBorder);
      ctx.font = `700 11px ${MONO}`;
      ctx.fillStyle = t.subtle;
      ctx.fillText(labelText, x + 16, y + 24);
      ctx.font = `900 34px ${MONO}`;
      ctx.fillStyle = t.text;
      ctx.fillText(value, x + 16, y + 66);
      if (note) {
        ctx.font = `600 10px ${MONO}`;
        ctx.fillStyle = t.muted;
        ctx.fillText(note, x + 16, y + 94);
      }
    }

    drawStatBox("Total Listings", String(totalListings || "—"), contentX, contentY, "Lifetime listings");
    drawStatBox("Current Listings", String(validListings || "—"), contentX + (contentWidth + 20) / 2, contentY, "Active listings");
    drawStatBox("Avg. Markup", fmtPercent(avgMarkupPercent), contentX, contentY + 130, "Premium over median");
    drawStatBox("Overpriced", fmtPercent(overpricedRatio, true), contentX + (contentWidth + 20) / 2, contentY + 130, "% above 110% median");

    // Bottom section: risk bar + top items hint
    const riskY = contentY + 280;
    drawLabel(ctx, "MARKUP RISK", contentX, riskY, t.muted);

    const riskBarY = riskY + 24;
    const riskBarWidth = contentWidth;
    const riskVal = Math.min(1, Math.max(0, ((avgMarkupPercent || 0) + 50) / 150));
    const riskColor = riskVal > 0.7 ? t.red : riskVal > 0.4 ? t.amber : t.green;
    fillRoundRect(ctx, contentX, riskBarY, riskBarWidth, 14, 4, t.cardBg, t.cardBorder);
    fillRoundRect(ctx, contentX, riskBarY, riskBarWidth * riskVal, 14, 4, riskColor + "40", riskColor);

    ctx.font = `600 10px ${MONO}`;
    ctx.fillStyle = t.muted;
    ctx.fillText("Higher markup = higher risk of overpaying", contentX, riskBarY + 32);

    // Status
    const statusY = riskBarY + 56;
    ctx.font = `700 11px ${MONO}`;
    ctx.fillStyle = isBlacklisted ? t.red : t.green;
    const status = isBlacklisted ? "BLOCKED SELLER" : "ACTIVE";
    fillRoundRect(ctx, contentX, statusY, 160, 24, 6, isBlacklisted ? t.red + "1A" : t.green + "1A", isBlacklisted ? t.red + "66" : t.green + "66");
    ctx.textAlign = "center";
    ctx.fillText(status, contentX + 80, statusY + 18);
    ctx.textAlign = "left";

    // Footer
    ctx.font = `700 10px ${MONO}`;
    ctx.fillStyle = t.muted;
    ctx.fillText("CASTIA MARKET INSIGHT", 56, v.height - 18);
    ctx.textAlign = "right";
    ctx.fillText("CMI", v.width - 56, v.height - 18);
    ctx.textAlign = "left";

    canvas.toBlob((blob) => {
      if (blob) resolve(blob);
      else reject(new Error("PNG export failed"));
    }, "image/png");
  });
}

function fmtPercent(n, isFraction = false) {
  if (n == null) return "—";
  const val = isFraction ? n * 100 : n;
  return `${val >= 0 ? "+" : ""}${val.toFixed(1)}%`;
}

export async function downloadSellerCard(seller) {
  const blob = await renderSellerCardToBlob(seller);
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = `${(seller.name || "seller").replace(/\s+/g, "-")}-trading-card.png`;
  a.click();
  setTimeout(() => URL.revokeObjectURL(url), 1000);
}
